import sys

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def searchBST(self, root: TreeNode, val: int) -> int:
        if not root:
            return -1
        if root.val == val:
            return val
        elif root.val < val:
            return self.searchBST(root.right, val)
        else:
            return self.searchBST(root.left, val)

if __name__ == '__main__':
    it = iter(sys.stdin.read().splitlines())
    try:
        n = int(next(it))
        root = None
        for _ in range(n):
            val = int(next(it))
            if not root:
                root = TreeNode(val)
            else:
                node = root
                while True:
                    if val < node.val:
                        if not node.left:
                            node.left = TreeNode(val)
                            break
                        node = node.left
                    else:
                        if not node.right:
                            node.right = TreeNode(val)
                            break
                        node = node.right
        target = int(next(it))
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.searchBST(root, target)
    print(ans)

