#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    int searchBST(TreeNode* root, int val) {
        if (!root) return -1;
        if (root->val == val) return val;
        if (root->val < val) return searchBST(root->right, val);
        return searchBST(root->left, val);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    TreeNode* root = nullptr;
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        if (!root) {
            root = new TreeNode(val);
        } else {
            TreeNode* node = root;
            while (true) {
                if (val < node->val) {
                    if (!node->left) {
                        node->left = new TreeNode(val);
                        break;
                    }
                    node = node->left;
                } else {
                    if (!node->right) {
                        node->right = new TreeNode(val);
                        break;
                    }
                    node = node->right;
                }
            }
        }
    }
    int target;
    cin >> target;
    Solution sol;
    int ans = sol.searchBST(root, target);
    cout << ans << '\n';
    return 0;
}
